import React from "react";
import {
  MdDashboard,
  MdViewList,
  MdExitToApp,
  MdEdit,
  MdDelete,
} from "react-icons/md";
import SunEditor, { buttonList } from "suneditor-react";
import "suneditor/dist/css/suneditor.min.css";
import { Button, Input, Alert, Badge, Menu, Dropdown } from "antd";
import "./index.css";
import { FaHtml5, FaNodeJs, FaReact, FaCss3, FaJs } from "react-icons/fa";
import { HOST } from "../../env";

const icons = [
  {
    name: "NodeJS",
    icon: <FaNodeJs color="green" fontSize={16} style={{marginTop:"3px"}} />,
  },
  {
    name: "HTML5",
    icon: <FaHtml5 color="orange" fontSize={16} style={{marginTop:"3px"}} />,
  },
  {
    name: "ReactJS",
    icon: <FaReact color="dodgerblue" fontSize={16} style={{marginTop:"3px"}} />,
  },
  {
    name: "CSS3",
    icon: <FaCss3 color="dodgerblue" fontSize={16} style={{marginTop:"3px"}} />,
  },
  {
    name: "Javascript",
    icon: <FaJs color="#d9d930" fontSize={16} style={{marginTop:"3px"}} />,
  },
];

const icon_options = (icons, update_icon) => {
  return icons.map((item) => {
    return (
      <Menu.Item key={item.name} onClick={() => update_icon(item.icon,item.name)}>
        {item.icon} {item.name}
      </Menu.Item>
    );
  });
};

const toPath = (value) => value.toLowerCase().split(" ").join("-");

const WithLoading = (Component) => ({ isLoading, children, ...rest }) => {
  return isLoading ? (
    <Component loading {...rest}>
      {children}
    </Component>
  ) : (
    <Component {...rest}>{children}</Component>
  );
};

const ButtonWithLoading = WithLoading(Button);

class Editor extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      title: "",
      content: "",
      error: "",
      publishing: false,
      path: "",
      active_icon: '',
      icon_name: '',
      description: ''
    };
    this.refContent = React.createRef();
    this.handleContent = this.handleContent.bind(this);
    this.handleTitle = this.handleTitle.bind(this);
    this.handlePublish = this.handlePublish.bind(this);
    this.handlePath = this.handlePath.bind(this);
    this.handleDescription = this.handleDescription.bind(this);
  }

  handleActiveIcon(icon,name) {
    this.setState({
      active_icon: icon,
      icon_name: name
    })
  }

  handleDescription(event) {
    this.setState({
      description: event.target.value
    })
  }

  handleTitle(event) {
    this.setState({
      title: event.target.value,
      path: toPath(event.target.value),
    });
  }

  handleContent(content) {
    this.setState({
      content,
    });
  }

  handlePath(event) {
    this.setState({
      path: toPath(event.target.value),
    });
  }

  handlePublish() {
    const { title, content, path, description, icon_name } = this.state;
    const options = {
      method: "POST",
      body: `title=${title}&content=${content}&path=${path}&description=${description}&icon=${icon_name}`,
      headers: {
        "Content-Type": "application/x-www-form-urlencoded; charset=UTF-8",
      },
    };
    this.setState({
      publishing: true,
    });
    fetch(`${HOST}/wgo-api/insert_post.php`, options)
      .then((response) => response.json())
      .then((response) => {
        if (response.message === "OK") {
          this.refContent.current.editor.setContents("");
          this.setState({
            publishing: false,
          });
          this.props.handleChanges();
        }
      })
      .catch((error) => {
        this.setState({
          error: error.message
        });
      });
  }

  menu = (<Menu>{icon_options(icons,this.handleActiveIcon.bind(this))}</Menu>);

  render() {
    const { error, path, publishing, active_icon,description } = this.state;

    return (
      <>
        {error ? (
          <Alert
            message={error}
            showIcon
            type="error"
            style={{ marginBottom: "10px" }}
          >
            sample
          </Alert>
        ) : null}
        <h1>Editor</h1>
        <div style={{ marginBottom: "10px" }}>
          <Input
            value={path}
            style={{ fontFamily: "courier new" }}
            onChange={this.handlePath}
            placeholder="Path"
          />
        </div>
        <div align="right" style={{ display: "flex", marginBottom: "10px" }}>
          <Input onChange={this.handleTitle} placeholder="Blog Title" />
          <ButtonWithLoading
            isLoading={publishing}
            onClick={this.handlePublish}
            style={{ marginLeft: "10px" }}
          >
            Publish
          </ButtonWithLoading>
        </div>
        <div style={{ marginBottom: "10px" }}>
          <Input
            value={description}
            onChange={this.handleDescription}
            placeholder="Brief Description"
          />
        </div>
        <div style={{ marginBottom: "10px"}}>
          <Dropdown overlay={this.menu}>
            <Button style={{display:"flex"}}>{active_icon} Select Icon</Button>
          </Dropdown>
        </div>
        <SunEditor
          ref={this.refContent}
          onChange={this.handleContent}
          placeholder="Write the way you want it"
          setOptions={{
            height: 500,
            buttonList: buttonList.complex,
          }}
        />
        <br />
      </>
    );
  }
}

const ListView = ({ listItem, handleChanges }) => {
  const handleDelete = (ID) => {
    fetch(`${HOST}/wgo-api/remove_post.php`, {
      method: "POST",
      headers: {
        "Content-Type": "application/x-www-form-urlencoded; charset=UTF-8",
      },
      body: `ID=${ID}`,
    })
      .then((response) => response.json())
      .then((response) => {
        if (response.message === "OK") {
          handleChanges();
        }
      })
      .catch((error) => console.log(error));
  };

  return (
    <>
      <ul className="list-container">
        {listItem.eachPosts.map((item) => {
          return (
            <li key={item.post_id}>
              <div href="#" className="list-item" style={{ display: "flex", alignItems: "center" }}>
                <div style={{ width: "80%" }}>{item.post_title}</div>
                <div style={{ width: "20%", textAlign: "end" }}>
                  <Button
                    onClick={() => handleDelete(item.post_id)}
                    className="post-action"
                  >
                    <MdDelete />
                  </Button>
                  <Button className="post-action">
                    <MdEdit />
                  </Button>
                </div>
              </div>
            </li>
          );
        })}
      </ul>
    </>
  );
};

const Posts = ({ data, handleChanges }) => {
  return (
    <>
      {data.message ? (
        <>
          <h1>
            Posts{" "}
            <Badge
              count={0}
              showZero
              style={{
                backgroundColor: "transparent",
                color: "#cc2828",
                border: "1px solid #cc2828",
              }}
            />
          </h1>
          <Alert
            description="No Available Posts"
            type="error"
            style={{ textAlign: "center" }}
          />
        </>
      ) : (
        <>
          <h1>
            Posts{" "}
            <Badge
              count={data.eachPosts.length}
              style={{
                backgroundColor: "transparent",
                color: "#cc2828",
                border: "1px solid #cc2828",
              }}
            />
          </h1>
          <ListView handleChanges={handleChanges} listItem={data} />
        </>
      )}
    </>
  );
};

class Admin extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      activeComponent: "",
      postsHasChanges: false,
      posts: "",
    };
    this.handleActiveComponent = this.handleActiveComponent.bind(this);
    this.handlePosts = this.handlePosts.bind(this);
    this.handlePostChanges = this.handlePostChanges.bind(this);
    this.handleRemove = this.handleRemove.bind(this);
  }

  handleActiveComponent(component) {
    this.setState({
      activeComponent: component,
    });
  }

  handlePostChanges() {
    this.setState({
      postsHasChanges: false,
    });
  }

  handleRemove() {
    this.handlePostChanges();
    this.handlePosts();
  }

  handlePosts() {
    if (!this.state.postsHasChanges) {
      fetch(`${HOST}/wgo-api/fetch_posts.php`)
        .then((response) => response.json())
        .then((posts) => {
          if (posts.message === "No Posts") {
            this.setState({
              posts,
              activeComponent: <Posts data={posts} />,
              postsHasChanges: true,
            });
          } else {
            this.setState({
              posts,
              activeComponent: (
                <Posts data={posts} handleChanges={this.handleRemove} />
              ),
              postsHasChanges: true,
            });
          }
        })
        .catch((error) => console.log(error));
    } else {
      this.setState({
        activeComponent: (
          <Posts data={this.state.posts} handleChanges={this.handleRemove} />
        ),
      });
    }
  }

  render() {
    return (
      <div className="wrapper">
        <div className="navigation">
          <nav>
            <ul>
              <li>
                <div className="nav">
                  <MdDashboard fontSize="16pt" />
                  <span>Dashboard</span>
                </div>
              </li>
              <li>
                <div
                  className="nav"
                  onClick={() =>
                    this.handleActiveComponent(
                      <Editor handleChanges={this.handlePostChanges} />
                    )
                  }
                >
                  <MdEdit fontSize="16pt" />
                  <span>Editor</span>
                </div>
              </li>
              <li>
                <div className="nav" onClick={this.handlePosts}>
                  <MdViewList fontSize="16pt" />
                  <span>Posts</span>
                </div>
              </li>
              <li>
                <div className="nav">
                  <MdExitToApp fontSize="16pt" />
                  <span>Logout</span>
                </div>
              </li>
            </ul>
          </nav>
        </div>
        <div className="panel">{this.state.activeComponent}</div>
      </div>
    );
  }
}

export default Admin;
