import styled from "styled-components";
const Wrapper = styled.div`
  width: 100%;
  padding: 50px 5%;
`;

const GridContainer = styled.div``;

const PostSection = styled.main``;

const AboutSection = styled.aside``;

const AdsContainer = styled.div`
  background-color: white;
  border-radius: 3px;
  padding: 10px;
  box-shadow: 0 4px 4px 1px rgba(0, 0, 0, 0.1);
  margin-bottom: 30px;
`;

const ProfileContainer = styled.div`
  width: 100%;
  padding: 10px 20px;
  background-color: white;
  box-shadow: 0 4px 4px 1px rgba(0, 0, 0, 0.1);
  border-radius: 3px;
  border-top: 4px solid #cc2828;
  display: flex;
  align-items: start;
  margin-bottom: 10px;
`;

const TopicsContainer = styled.main`
  padding: 20px 5%;
  margin-bottom:20px;
`;

const TopicsHeader = styled.h1`
  color: #575757;
  margin-top: 40px;
  margin-bottom: 10px;
  @media (max-width: 510px) {
    font-size: 14pt;
  }
`;

const TopicsSubHeader = styled.h2`
  color: #575757;
  margin-top: 10px;
  margin-bottom: 50px;
  text-indent: 20px;
  @media (max-width: 510px) {
    font-size: 14pt;
  }
`;

const PostContainer = styled.div`
  background-color: white;
  box-shadow: 0 4px 4px 1px rgba(0, 0, 0, 0.1);
  width: 100%;
  padding: 20px 40px;
  border-radius: 3px;
  margin-bottom: 20px;
  border-top: 4px solid #cc2828;
  @media (max-width: 510px) {
    border-top: none;
    // border-bottom: 4px solid #cc2828;
    // padding: 15px 25px;
    padding: 0;
    box-shadow: none;
    margin-top:30px;
  }
`;

const PostTitle = styled.h1`
  color: #575757;
  font-family: "msrtmedium";
  margin: 20px 0px 10px 0;
  font-weight:bold;
  @media (max-width: 510px) {
    font-size: 12.5pt;
  }
`;

const PostArticle = styled.article`
  text-align: justify;
  font-size: 10pt;
  line-height: 1.5;
  font-family: "msrtthin";
  color: #575757;
  word-break: break-word;
`;

const PostParagraph = styled.p`
  font-weight: normal;
  font-size: 10.5pt;
  font-family: msrtthin;
`;

const LoginContainer = styled.div`
  width: 100%;
  height: 80vh;
  display: grid;
  grid-template-columns: 1fr;
  justify-items: center;
  align-items: center;
`;

const LoginPanel = styled.div`
  width: 20%;
  //   border: 1px solid #dbdbdb;
  border-radius: 3px;
  box-shadow: 0 2px 5px 1px rgba(0, 0, 0, 0.15);
  background-color: white;
  @media (max-width: 510px) {
    width: 80%;
  }
`;

const LoginHeader = styled.div`
  width: 100%;
  background-color: #cc2828;
  padding: 10px;
  color: white;
  border-top-left-radius: 3px;
  border-top-right-radius: 3px;
`;

const LoginInputs = styled.div`
  width: 100%;
  padding: 20px;
`;

const CommentSection = styled.section`
  background-color: white;
  padding: 10px 0;
`;

const Comment = styled.article`
  background-color: white;
  padding: 0 10px;
  word-break:break-word;
  margin-bottom: 10px;
  border-bottom: 1px solid #eaeaea
`;

export {
  Wrapper,
  GridContainer,
  PostSection,
  AdsContainer,
  AboutSection,
  ProfileContainer,
  PostContainer,
  PostTitle,
  PostArticle,
  TopicsContainer,
  TopicsHeader,
  PostParagraph,
  LoginContainer,
  LoginPanel,
  LoginHeader,
  LoginInputs,
  TopicsSubHeader,
  CommentSection,
  Comment,
};
