import React from "react";
import { useParams } from "react-router-dom";
import { Profile, Post, NavigatorPanel, Socials } from "../index";
import { SOCIALS } from "../../env";

import "./index.blog.css";

import {
  Wrapper,
  GridContainer,
  PostSection,
  AboutSection,
} from "../../styled";

const Blog = () => {
  let { topic } = useParams();
   return (
    <>
      <NavigatorPanel />
      <Wrapper>
        <GridContainer className="forGrid">
          <PostSection>
            <Profile className="forPost" />
            <Post path={topic} />
          </PostSection>
          <AboutSection>
            <Profile className="forAbout" />
            <Socials socials={SOCIALS} />
          </AboutSection>
        </GridContainer>
      </Wrapper>
    </>
  );
};

export default Blog;
