import React from "react";
import { FaUser, FaKey } from "react-icons/fa";  
import { Input, Button } from "antd";

import {
  LoginContainer,
  LoginHeader,
  LoginInputs,
  LoginPanel,
} from "../../styled";

class Login extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      username: "",
      password: "",
    };
    this.handleUnameChange = this.handleUnameChange.bind(this);
    this.handleUpassChange = this.handleUpassChange.bind(this);
    this.handleEnter = this.handleEnter.bind(this);
  }

  handleUnameChange(event) {
    this.setState({
      username: event.target.value,
    });
  }

  handleUpassChange(event) {
    this.setState({
      password: event.target.value,
    });
  }

  handleEnter() {
    
  }

  render() {
    return (
      <LoginContainer>
        <LoginPanel>
          <LoginHeader>
            <h1
              style={{
                margin: "3px 5px",
                fontSize: "10pt",
                letterSpacing: "2px",
                color: "white",
                fontFamily: "origami",
              }}
            >
              LOGIN
            </h1>
          </LoginHeader>
          <LoginInputs>
            <form>
              <label htmlFor="uname">Username: </label>
              <Input
                onChange={this.handleUnameChange}
                type="text"
                id="uname"
                placeholder="Enter Your Username"
                style={{
                  width: "100%",
                  fontWeight: "normal",
                  fontSize: "9pt",
                  marginBottom: "10px",
                  marginTop: "5px",
                }}
                prefix={<FaUser />}
              />
              <label htmlFor="upass">Password: </label>
              <Input
                onChange={this.handleUpassChange}
                type="password"
                id="upass"
                placeholder="Enter Your Password"
                style={{
                  width: "100%",
                  fontWeight: "normal",
                  fontSize: "9pt",
                  marginBottom: "10px",
                  marginTop: "5px",
                }}
                prefix={<FaKey />}
              />
              <Button block style={{ marginTop: "10px" }}>
                Enter
              </Button>
            </form>
          </LoginInputs>
        </LoginPanel>
      </LoginContainer>
    );
  }
}

export default Login;