import React from "react";
import { FaChevronDown } from 'react-icons/fa';
import {
  Link,
} from "react-router-dom";

const NavigatorPanel = () => {
  let navbar = React.useRef();
  let mobileNav = React.useRef();

  const handleMobileMenu = (DOM) => {
    if (navbar.current.style.display === "block") {
      navbar.current.style.display = "none";
      mobileNav.current.firstChild.style.transform = "rotate(0deg)";
    } else {
      navbar.current.style.display = "block";
      mobileNav.current.firstChild.style.transform = "rotate(180deg)";
    }
    navbar.current.style.justifySelf = "start";
    navbar.current.style.width = "100%";
    navbar.current.style.gridRowStart = "2";
    navbar.current.style.gridRowEnd = "2";
    navbar.current.style.gridColumnStart = "1";
    navbar.current.style.gridColumnEnd = "3";
  };

  return (
    <nav className="navigator">
      <ul className="navigator-nav">
        <li className="nav-list logo-nav">
          <Link to="/" className="logo">
            <img src="/logo2.png" alt="logic package logo" width="25" />{" "}LOGIC PACKAGE
          </Link>
        </li>
      </ul>
      <ul className="navigator-nav menu">
        <li className="nav-list">
          <div className="nav-link" onClick={handleMobileMenu} ref={mobileNav}>
            <FaChevronDown />
          </div>
        </li>
      </ul>
      <ul className="navigator-nav normal" ref={navbar}>
        <li className="nav-list">
          <Link to="/" className="nav-link">
            Home
          </Link>
        </li>
        <li className="nav-list">
          <a href="/blog/page/1" className="nav-link">
            Blog
          </a>
        </li>
        <li className="nav-list">
          <Link to="/about" className="nav-link">
            About
          </Link>
        </li>
        <li className="nav-list">
          <Link to="/contact" className="nav-link">
            Contact
          </Link>
        </li>
      </ul>
    </nav>
  );
};

export default React.memo(NavigatorPanel);
