import React from "react";
import { BrowserRouter as Router, Switch, Route } from "react-router-dom";
import "./App.css";
import { NavigatorPanel, Blog, Admin, Topics, About,Home,Contact,Footer, Privacy } from "./Components/index";

const App = () => {
  return (
    <>
      <Router>
        <Switch>
          <Route exact path="/blog/:topic">
            <Blog />
            <Footer />
          </Route>
          <Route exact path="/blog/page/:pagenumber">
            <NavigatorPanel />
            <Topics />
            <Footer />
          </Route>
          <Route exact path="/contact">
            <NavigatorPanel />
            <Contact />
            <Footer />

          </Route>
          <Route exact path="/">
            <NavigatorPanel />
            <Home />
            <Footer />

          </Route>
          <Route exact path="/about">
            <NavigatorPanel />
            <About />
            <Footer />

          </Route>
          <Route exact path="/admin">
            <Admin />
          </Route>
          <Route exact path="/privacy-policy">
            <NavigatorPanel />
            <Privacy />
          </Route>
          <Route exact path="/301">
            <h1>Redirected!</h1>
          </Route>
        </Switch>
      </Router>
    </>
  );
};

export default App;
