import React from "react";
import "./index.home.css";
import { Helmet } from 'react-helmet';

const Home = () => {
  return (
    <div
      className="grid-home"
    >
      <Helmet>
          <meta
          name="title"
          content="Logic Package"
        />
        <meta name="description" content="Website for computer related articles such as computer programming, electronics, mathematics, and other logical stuffs" />
        <title>Logic Package | Home</title>
      </Helmet>
      {/* <img src="/logo2.png" /> */}
      <div className="greet" style={{alignSelf:"center"}}>
        <h1 style={{ color: "white",fontSize:"25pt" }}>
          Logic Package
        </h1>
        <h2 style={{color:"#e6e6e6",fontSize:"14pt"}}>
          Logically packed articles just for you
        </h2>
        <a href="/blog/page/1" rel="noopener noreferrer" style={{boxShadow:"0 4px 10px 1px rgba(0,0,0,0.2)",padding:"10px 15px",display:"inline-block",border:"1px solid rgb(210, 207, 207)",color:"white",borderRadius:"3px"}}>Go To Articles</a>
      </div>
      <div className="logo-home" style={{textAlign:"center",alignSelf:"center"}}>
        <img src="/logo2.png" width="250" alt="logic package logo"/>
      </div>
    </div>
  );
};

export default Home;