import React from "react";
import "./index.socials.css";
import { FaTwitter, FaFacebookF, FaGoogle } from "react-icons/fa";

const Socials = ({ socials }) => {
  return (
    <div className="socials-container">
      <h1>Reach Me Out</h1>
      {socials.map((item) => {
        if (item.icon === "facebook")
          return (
            <a style={{backgroundColor:"#145da4"}} href={item.link} target="_blank" rel="noopener noreferrer" key={item.icon} title="Facebook Account" className="socials">
              <FaFacebookF />
            </a>
          );
        else if (item.icon === "twitter")
          return (
            <a style={{backgroundColor:"#43c1ea"}} href={item.link} target="_blank" rel="noopener noreferrer" key={item.icon} title="Twitter Account" className="socials">
              <FaTwitter />
            </a>
          );
        else if (item.icon === "google")
          return (
            <a style={{backgroundColor:"#cc2828"}} href={item.link} target="_blank" rel="noopener noreferrer" key={item.icon} title="Email Address" className="socials">
              <FaGoogle />
            </a>
          );
        else 
            return (null);
      })}
    </div>
  );
};

export default React.memo(Socials);
