import React from "react";
import { FaChevronRight } from "react-icons/fa";
import { PostContainer, PostTitle, PostArticle } from "../../styled";
import "antd/dist/antd.min.css";
import { Skeleton } from "antd";
import { HOST } from "../../env";
import { Redirect, Link } from "react-router-dom";
import { Helmet } from 'react-helmet';
import './index.post.css';

class Post extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      title: "",
      content: "",
      error: "",
      date: "",
      description: ''
    };
    this.refContent = React.createRef();
  }

  componentDidMount() {
    fetch(`${HOST}/wgo-api/fetch_specific.php?path=${this.props.path}`)
      .then((response) => response.json())
      .then((response) => {
        this.setState({
          content: response.post_content,
          title: response.post_title,
          date: response.post_date,
          description: response.post_description
        });
        this.refContent.current.innerHTML = response.post_content;
        // this.props.handlePostID(response.post_id)
      })
      .catch((error) =>
        this.setState({
          error,
        })
      );
  }

  render() {
    const { title, content, error, date, description } = this.state;

    if (error) {
      return <Redirect to="/301" />;
    }

    return (
      <PostContainer>
        <Helmet>
          <meta name="title" content={title} />
          <meta name="description" content={description} />
          <title>{title} | Logic Package</title>
        </Helmet>
        <div className="sharethis-inline-share-buttons" style={{marginBottom:"20px"}}></div>
        {
          content ?
          <PostArticle className="article-container">
            <header style={{marginBottom:"30px"}}>
              <small style={{ textTransform: "capitalize", color: "gray" }}>
                <Link rel="noindex nofollow" to="/" style={{ color: "gray" }}>
                  Home
                </Link>{" "}
                <FaChevronRight size="8" />{" "}
                <a rel="noindex nofollow" href="/blog/page/1" style={{ color: "gray" }}>
                  Blog
                </a>{" "}
                <FaChevronRight size="8" /> {this.props.path.split("-").join(" ")}
              </small>
              <PostTitle>{title}</PostTitle>
              <p style={{ color: "gray", fontSize: "9pt" }}>
                <time dateTime={date} style={{fontSize:"9pt"}}>Posted: {date ? new Date(date).toUTCString() : "..."}</time>
              </p>
            </header>
            <div ref={this.refContent}></div>
          </PostArticle>
          : <Skeleton active />
        }
      </PostContainer>
    );
  }
}

export default React.memo(Post);
