import React from "react";
import { TopicsContainer, TopicsHeader, TopicsSubHeader } from "../../styled";
import "./index.topics.css";
import { HOST } from "../../env";
import { useParams, Redirect } from "react-router-dom";
import { Skeleton } from "antd";
import { Helmet } from "react-helmet";
import { FaChevronRight, FaChevronLeft } from "react-icons/fa";

const Topics = () => {
  let [topics, setTopics] = React.useState([]);
  let { pagenumber } = useParams();
  let [error, setError] = React.useState(false);

  React.useEffect(() => {
    fetch(`${HOST}/wgo-api/fetch_posts.php?page=${pagenumber}`)
      .then((response) => response.json())
      .then((fetched) => {
        setTopics(fetched);
      })
      .catch((error) => setError(true));
  }, [pagenumber]);

  if (error) {
    return <Redirect to="/" />;
  }

  return (
    <TopicsContainer>
      <Helmet>
        <meta name="title" content="Blog" />
        <meta
          name="description"
          content="Website for computer related articles such as computer programming, electronics, mathematics, and other logical stuffs"
        />
        <title>Logic Package | Blog</title>
      </Helmet>
      <header>
        <TopicsHeader>Technology Articles</TopicsHeader>
        <TopicsSubHeader>Topics you might want to read</TopicsSubHeader>
      </header>
      {topics.eachPosts ? (
        <div className="grid-wrapper">
          {" "}
          {topics.eachPosts.map((item) => {
            return (
              <section className="flex-wrapper-blog" key={item.post_id}>
                <a href={`/blog/${item.path}`} className="topics-item">
                  {item.post_title}
                </a>
                <div className="topics-image">
                  <img
                    src={`/icons/${item.post_icon}.svg`}
                    alt={`${item.post_icon} Icon`}
                    draggable={false}
                  />
                </div>
              </section>
            );
          })}
        </div>
      ) : topics.message ? (
        <div
          style={{
            textAlign: "center",
            backgroundColor: "rgba(200, 46, 46, 0.16)",
            padding: "10px",
            borderRadius: "3px",
            border: "1px solid rgb(221, 162, 162)",
          }}
        >
          <h1
            style={{ fontSize: "12pt", margin: 0, color: "rgb(196, 104, 104)" }}
          >
            No Available Topics
          </h1>
        </div>
      ) : (
        <>
          <Skeleton active paragraph={1} avatar />
          <Skeleton active paragraph={1} avatar />
          <Skeleton active paragraph={1} avatar />
        </>
      )}
      <div
        style={{ display: "grid", justifyContent: "center", marginTop: "40px" }}
      >
        <div className="pages-link-container">
          {parseInt(pagenumber) !== 1 ? (
            <a
              href={`/blog/page/${parseInt(pagenumber) - 1}`}
              className="next-page"
            >
              <span>
                <FaChevronLeft style={{ alignSelf: "center" }} />
                Prev
              </span>
            </a>
          ) : null}
          {parseInt(topics.wholePostsCount) >= parseInt(pagenumber) * 10 ? (
            <a
              href={`/blog/page/${parseInt(pagenumber) + 1}`}
              className="next-page"
            >
              <span>
                Next
                <FaChevronRight style={{ alignSelf: "center" }} />
              </span>
            </a>
          ) : null}
        </div>
      </div>
    </TopicsContainer>
  );
};

export default Topics;
